// Cross-language parity tests for byte-payload encoding/decoding.
//
// Reads fixtures generated by Rust at
// `rivetkit-rust/packages/rivetkit/tests/fixtures/encoding/*.json` (run
// `cargo test -p rivetkit --test encoding_fixtures` to regenerate) and
// asserts that:
// 1. TS `encodeJsonCompatValue` produces the same wire shape on the same
//    input (encode parity).
// 2. TS `reviveJsonCompatValue` revives Rust-encoded bytes to a real
//    `Uint8Array` with the original contents (decode parity).
//
// If this test fails, the Rust framework and the TS framework have
// drifted apart on the wire convention — fix whichever side disagrees.

import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, expect, test } from "vitest";
import {
	encodeJsonCompatValue,
	reviveJsonCompatValue,
} from "@/common/encoding";

const FIXTURE_DIR = join(
	__dirname,
	"../../../../rivetkit-rust/packages/rivetkit/tests/fixtures/encoding",
);

function loadFixture(name: string): unknown {
	const raw = readFileSync(join(FIXTURE_DIR, `${name}.json`), "utf8");
	return JSON.parse(raw);
}

describe("byte-encoding parity (Rust ⇄ TS)", () => {
	test("uint8array_hello fixture matches TS encode output", () => {
		const rustEncoded = loadFixture("uint8array_hello");
		const tsEncoded = encodeJsonCompatValue(
			new Uint8Array([0x68, 0x65, 0x6c, 0x6c, 0x6f]), // "hello"
		);
		expect(rustEncoded).toEqual(tsEncoded);
	});

	test("uint8array_1234 fixture matches TS encode output", () => {
		const rustEncoded = loadFixture("uint8array_1234");
		const tsEncoded = encodeJsonCompatValue(new Uint8Array([1, 2, 3, 4]));
		expect(rustEncoded).toEqual(tsEncoded);
	});

	test("struct_with_byte_field fixture matches TS encode output", () => {
		const rustEncoded = loadFixture("struct_with_byte_field");
		const tsEncoded = encodeJsonCompatValue({
			status: 200,
			body: new Uint8Array([0x6f, 0x6b]), // "ok"
		});
		expect(rustEncoded).toEqual(tsEncoded);
	});

	test("plain string is unchanged across languages", () => {
		const rustEncoded = loadFixture("plain_string");
		const tsEncoded = encodeJsonCompatValue("hello world");
		expect(rustEncoded).toEqual(tsEncoded);
	});

	test("TS reviveJsonCompatValue handles Rust-encoded uint8array_hello", () => {
		const rustEncoded = loadFixture("uint8array_hello");
		const revived = reviveJsonCompatValue(rustEncoded);
		expect(revived).toBeInstanceOf(Uint8Array);
		expect(new TextDecoder().decode(revived as Uint8Array)).toBe("hello");
	});

	test("TS reviveJsonCompatValue handles Rust-encoded uint8array_1234", () => {
		const rustEncoded = loadFixture("uint8array_1234");
		const revived = reviveJsonCompatValue(rustEncoded);
		expect(revived).toBeInstanceOf(Uint8Array);
		expect([...revived]).toEqual([1, 2, 3, 4]);
	});

	test("TS reviveJsonCompatValue handles Rust-encoded nested byte field", () => {
		const rustEncoded = loadFixture("struct_with_byte_field");
		const revived = reviveJsonCompatValue(rustEncoded) as {
			status: number;
			body: Uint8Array;
		};
		expect(revived.status).toBe(200);
		expect(revived.body).toBeInstanceOf(Uint8Array);
		expect(new TextDecoder().decode(revived.body)).toBe("ok");
	});
});
